import React, { useState, useRef, useEffect } from 'react';
import { useCalendar } from '../context/CalendarContext';
import '../styles/ChatInterface.css';

const ChatInterface = () => {
    const [messages, setMessages] = useState([]);
    const [inputValue, setInputValue] = useState('');
    const [pendingTask, setPendingTask] = useState(null);
    const [pendingEdit, setPendingEdit] = useState(null);
    const messagesEndRef = useRef(null);
    const { addTask, updateTask, setIsCalendarExpanded } = useCalendar();

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    };

    useEffect(() => {
        scrollToBottom();
    }, [messages]);

    const formatAIResponse = (data) => {
        if (data.error) return `Sorry, I couldn't process that. ${data.error}`;
        
        // Split the date string and create a date object with local timezone
        const [year, month, day] = data.startDate.split('-').map(Number);
        const date = new Date(year, month - 1, day); // month is 0-based in JavaScript
        
        const formattedDate = date.toLocaleDateString('en-US', { 
            weekday: 'long', 
            year: 'numeric', 
            month: 'long', 
            day: 'numeric' 
        });

        // Use the same format for the bottom date
        const shortFormattedDate = date.toLocaleDateString('en-US', {
            year: 'numeric',
            month: 'numeric',
            day: 'numeric'
        });

        // Log the dates for debugging
        console.log('Original startDate:', data.startDate);
        console.log('Parsed date object:', date);
        console.log('Formatted date string:', formattedDate);
        console.log('Short formatted date:', shortFormattedDate);

        return `I've scheduled "${data.description}" for ${formattedDate}. Would you like me to: 1. Add more details to this task 2. Set up a reminder 3. Make it a recurring event\n${data.description}\n${formattedDate}`;
    };

    const generateSuggestions = (data) => {
        const suggestions = [
            "Add more details",
            "Set a reminder",
            "Make it recurring"
        ];

        if (data.recurrence) {
            suggestions.push("Change recurrence pattern");
        }

        return suggestions;
    };

    const handleSuggestionClick = (suggestion) => {
        switch (suggestion) {
            case "Add more details":
                setInputValue("Add more details to the task");
                break;
            case "Set a reminder":
                setInputValue("Set a reminder for this task");
                break;
            case "Make it recurring":
                setInputValue("Make this task recurring");
                break;
            default:
                setInputValue(suggestion);
        }
    };

    const handleTaskConfirmation = async () => {
        if (!pendingTask) return;

        try {
            // Ensure we have a start date, default to today if not provided
            const today = new Date().toISOString().split('T')[0];
            const formattedTask = {
                ...pendingTask,
                start_date: pendingTask.startDate || today,
                end_date: pendingTask.endDate || pendingTask.startDate || today,
                date: pendingTask.startDate || today,  // Add this for backend compatibility
                // Ensure all required fields are present
                title: pendingTask.title || pendingTask.description,
                description: pendingTask.description || pendingTask.title,
                time: pendingTask.time || '',
                color: pendingTask.color || '#2196F3'
            };

            console.log('Confirming task with data:', formattedTask);
            
            // Add task to calendar
            await addTask(formattedTask, false);
            
            // Add confirmation message
            setMessages(prev => [...prev, {
                type: 'assistant',
                content: `✅ Task "${formattedTask.title}" has been added to your calendar!`,
                timestamp: new Date()
            }]);

            // Expand calendar and highlight new task
            setIsCalendarExpanded(true);
            setPendingTask(null);

        } catch (error) {
            console.error('Error in task confirmation:', error);
            setMessages(prev => [...prev, {
                type: 'assistant',
                content: `Failed to confirm task: ${error.message}. Please try again.`,
                timestamp: new Date()
            }]);
        }
    };

    const handleEditConfirmation = async (selectedTask) => {
        if (!pendingEdit || !selectedTask) {
            console.error('Missing edit data or selected task');
            return;
        }

        try {
            // Log the update attempt
            console.log('Updating task:', selectedTask.group_id);
            console.log('Update data:', pendingEdit);

            // Send edit request to backend
            const response = await fetch('http://localhost:5000/api/tasks/edit', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    query: pendingEdit.original_input,
                    task_id: selectedTask.group_id
                })
            });

            if (!response.ok) {
                throw new Error(`Server error: ${response.status}`);
            }

            const result = await response.json();
            console.log('Edit response:', result);

            if (result.error) {
                throw new Error(result.error);
            }

            // Update task through CalendarContext using the updated task data
            if (result.updated_task) {
                await updateTask(selectedTask.group_id, result.updated_task);
            }

            // Add success message
            setMessages(prev => [...prev, {
                type: 'assistant',
                content: `✅ Task "${result.updated_task?.title || selectedTask.title}" has been updated!`,
                timestamp: new Date()
            }]);

            // Clear pending edit
            setPendingEdit(null);

            // Expand calendar to show changes
            setIsCalendarExpanded(true);

        } catch (error) {
            console.error('Error updating task:', error);
            setMessages(prev => [...prev, {
                type: 'assistant',
                content: `Failed to update task: ${error.message}. Please try again.`,
                timestamp: new Date()
            }]);
        }
    };

    const handleEditRequest = async (editData) => {
        try {
            const response = await fetch('http://localhost:5000/api/tasks/edit', {
                method: 'POST',
                headers: { 
                    'Content-Type': 'application/json',
                    'Accept': 'application/json'
                },
                body: JSON.stringify({ 
                    query: editData.original_input
                })
            });

            if (!response.ok) {
                throw new Error(`Server error: ${response.status}`);
            }

            const result = await response.json();
            console.log('Edit response:', result);

            if (result.error) {
                throw new Error(result.error);
            }

            // Store the pending edit
            setPendingEdit(result);

            // Add AI response for edit confirmation
            const aiMessage = {
                type: 'assistant',
                content: `I'll help you edit that task. Here's what I'm going to change:\n${result.changes.map(change => 
                    `- ${change.field}: ${change.value}`
                ).join('\n')}\n\nWould you like me to apply these changes? (yes/no)`,
                timestamp: new Date(),
                editDetails: result,
                confirmButton: true,
                confirmationType: 'edit'
            };

            setMessages(prev => [...prev, aiMessage]);
        } catch (error) {
            console.error('Error processing edit:', error);
            setMessages(prev => [...prev, {
                type: 'assistant',
                content: `Error: ${error.message}. Please try again or rephrase your request.`,
                timestamp: new Date()
            }]);
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (!inputValue.trim()) return;

        const userMessage = {
            type: 'user',
            content: inputValue,
            timestamp: new Date()
        };

        setMessages(prev => [...prev, userMessage]);
        const currentInput = inputValue.toLowerCase().trim();
        setInputValue('');

        // Handle edit confirmation
        if (pendingEdit && (currentInput === 'yes' || currentInput === 'y')) {
            await handleEditConfirmation();
            return;
        } else if (pendingEdit && (currentInput === 'no' || currentInput === 'n')) {
            setPendingEdit(null);
            setMessages(prev => [...prev, {
                type: 'assistant',
                content: 'Edit cancelled. Is there anything else I can help you with?',
                timestamp: new Date()
            }]);
            return;
        }

        try {
            const response = await fetch('http://localhost:5000/api/parse-task', {
                method: 'POST',
                headers: { 
                    'Content-Type': 'application/json',
                    'Accept': 'application/json'
                },
                body: JSON.stringify({ 
                    input: inputValue
                })
            });

            if (!response.ok) {
                throw new Error(`Server error: ${response.status}`);
            }

            const data = await response.json();
            console.log('Parsed response:', data);

            // Check if this is an edit request
            if (data.is_edit_request) {
                await handleEditRequest(data);
                return;
            }

            // Store the pending task
            setPendingTask(data);

            const aiMessage = {
                type: 'assistant',
                content: formatAIResponse(data),
                timestamp: new Date(),
                taskDetails: data,
                confirmButton: true,
                confirmationType: 'add',
                suggestions: generateSuggestions(data)
            };

            setMessages(prev => [...prev, aiMessage]);
        } catch (error) {
            console.error('Error processing message:', error);
            setMessages(prev => [...prev, {
                type: 'assistant',
                content: `Error: ${error.message}. Please try again or rephrase your request.`,
                timestamp: new Date()
            }]);
        }
    };

    return (
        <div className="chat-container">
            <div className="chat-messages">
                {messages.map((message, index) => (
                    <div key={index} className={`message ${message.type}`}>
                        <div className="message-content">{message.content}</div>
                        {message.taskDetails && (
                            <div className="task-preview">
                                <div className="task-details">
                                    <div className="task-title">{message.taskDetails.title}</div>
                                    <div className="task-date">
                                        {(() => {
                                            const [year, month, day] = message.taskDetails.startDate.split('-').map(Number);
                                            const date = new Date(year, month - 1, day);
                                            return date.toLocaleDateString('en-US', {
                                                year: 'numeric',
                                                month: 'numeric',
                                                day: 'numeric'
                                            });
                                        })()}
                                    </div>
                                </div>
                                {message.confirmButton && (
                                    <button 
                                        className="confirm-button"
                                        onClick={handleTaskConfirmation}
                                    >
                                        Confirm Task
                                    </button>
                                )}
                            </div>
                        )}
                        {message.suggestions && (
                            <div className="message-suggestions">
                                {message.suggestions.map((suggestion, i) => (
                                    <button 
                                        key={i} 
                                        onClick={() => handleSuggestionClick(suggestion)}
                                        className="suggestion-button"
                                    >
                                        {suggestion}
                                    </button>
                                ))}
                            </div>
                        )}
                    </div>
                ))}
                <div ref={messagesEndRef} />
            </div>
            <form onSubmit={handleSubmit} className="chat-input-form">
                <input
                    type="text"
                    value={inputValue}
                    onChange={(e) => setInputValue(e.target.value)}
                    placeholder="Type your message here..."
                    className="chat-input"
                />
                <button type="submit" className="send-button">
                    <svg viewBox="0 0 24 24" className="send-icon">
                        <path d="M2.01 21L23 12 2.01 3 2 10l15 2-15 2z" />
                    </svg>
                </button>
            </form>
        </div>
    );
};

export default ChatInterface;
